import tensorflow as tf

# TensorFlow's production edge: export to SavedModel for serving
class MyModel(tf.Module):
    def __init__(self):
        self.dense = tf.keras.layers.Dense(64, activation='relu')

    @tf.function(input_signature=[tf.TensorSpec(shape=[None, 128], dtype=tf.float32)])
    def serve(self, x):
        return self.dense(x)

model = MyModel()
tf.saved_model.save(model, '/tmp/my_model', signatures={'serving_default': model.serve})

# Load and run — no Python, no TF install needed on inference server
loaded = tf.saved_model.load('/tmp/my_model')
result = loaded.signatures['serving_default'](tf.ones([4, 128]))

import tensorflow as tf

class GatedLinearUnit(tf.keras.layers.Layer):
    def __init__(self, units, **kwargs):
        super().__init__(**kwargs)
        self.dense = tf.keras.layers.Dense(units * 2)

    def build(self, input_shape):
        self.dense.build(input_shape)
        super().build(input_shape)

    def call(self, x, training=False):
        projected = self.dense(x)
        values, gates = tf.split(projected, 2, axis=-1)
        return values * tf.nn.sigmoid(gates)

    def get_config(self):
        return {**super().get_config(), 'units': self.dense.units // 2}

# Drop-in with Functional API
inputs = tf.keras.Input(shape=(128,))
outputs = GatedLinearUnit(64)(inputs)
model = tf.keras.Model(inputs, outputs)

import tensorflow as tf
import tf2onnx

class MyModel(tf.keras.Model):
    @tf.function(input_signature=[tf.TensorSpec([None, 128], tf.float32, name='input')])
    def serve(self, x):
        return {'output': self(x, training=False)}

model = MyModel()
# Attach serving signature before export
model.serve = model.serve
tf.saved_model.save(model, './export/1', signatures={'serving_default': model.serve})

# Convert to ONNX (opset 17)
onnx_model, _ = tf2onnx.convert.from_saved_model('./export/1', opset=17, output_path='model.onnx')
